type DocumentStatus string

const (
	DocumentStatusStarted    DocumentStatus = "started"
	DocumentStatusProcessing DocumentStatus = "processing"
	DocumentStatusReady      DocumentStatus = "ready"
	DocumentStatusError      DocumentStatus = "error"
	DocumentStatusRecrawling DocumentStatus = "recrawling"
)

// AllValues returns all DocumentStatus values.
func (DocumentStatus) AllValues() []DocumentStatus {
	return []DocumentStatus{
		DocumentStatusStarted,
		DocumentStatusProcessing,
		DocumentStatusReady,
		DocumentStatusError,
		DocumentStatusRecrawling,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s DocumentStatus) MarshalText() ([]byte, error) {
	switch s {
	case DocumentStatusStarted:
		return []byte(s), nil
	case DocumentStatusProcessing:
		return []byte(s), nil
	case DocumentStatusReady:
		return []byte(s), nil
	case DocumentStatusError:
		return []byte(s), nil
	case DocumentStatusRecrawling:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *DocumentStatus) UnmarshalText(data []byte) error {
	switch DocumentStatus(data) {
	case DocumentStatusStarted:
		*s = DocumentStatusStarted
		return nil
	case DocumentStatusProcessing:
		*s = DocumentStatusProcessing
		return nil
	case DocumentStatusReady:
		*s = DocumentStatusReady
		return nil
	case DocumentStatusError:
		*s = DocumentStatusError
		return nil
	case DocumentStatusRecrawling:
		*s = DocumentStatusRecrawling
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

