type VideoStatus string

const (
	VideoStatusQueued     VideoStatus = "queued"
	VideoStatusGenerating VideoStatus = "generating"
	VideoStatusReady      VideoStatus = "ready"
	VideoStatusDeleted    VideoStatus = "deleted"
	VideoStatusError      VideoStatus = "error"
)

// AllValues returns all VideoStatus values.
func (VideoStatus) AllValues() []VideoStatus {
	return []VideoStatus{
		VideoStatusQueued,
		VideoStatusGenerating,
		VideoStatusReady,
		VideoStatusDeleted,
		VideoStatusError,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s VideoStatus) MarshalText() ([]byte, error) {
	switch s {
	case VideoStatusQueued:
		return []byte(s), nil
	case VideoStatusGenerating:
		return []byte(s), nil
	case VideoStatusReady:
		return []byte(s), nil
	case VideoStatusDeleted:
		return []byte(s), nil
	case VideoStatusError:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *VideoStatus) UnmarshalText(data []byte) error {
	switch VideoStatus(data) {
	case VideoStatusQueued:
		*s = VideoStatusQueued
		return nil
	case VideoStatusGenerating:
		*s = VideoStatusGenerating
		return nil
	case VideoStatusReady:
		*s = VideoStatusReady
		return nil
	case VideoStatusDeleted:
		*s = VideoStatusDeleted
		return nil
	case VideoStatusError:
		*s = VideoStatusError
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

